 class="container" id="report-root">    <div class="header">        <div>            <div class="title">Overview - <?= htmlspecialchars($All_Devicename[1] ?? $Query_IMEI) ?></div>            <div style="font-size:13px;color:#666;margin-top:4px">                HTSC : <?= htmlspecialchars($All_HTSC_No[1] ?? '') ?> &nbsp; | &nbsp;                Location : <?= htmlspecialchars($Site_Location[1] ?? '') ?>            </div>        </div>        <div class="controls">            <button class="btn" id="btnExportCSV">Export CSV</button>            <button class="btn secondary" id="btnExportPDF">Export PDF</button>            <button class="btn" id="btnPrint" onclick="window.print()">Print</button>        </div>    </div>    <div class="report-card">        <?php if ($XLS == 1) { ?>            <table class="compact-table" width="100%" border="1" cellspacing="0" cellpadding="4">                <tr><th colspan="4">Overview Report - <?= htmlspecialchars($IMEI) ?></th></tr>                <tr>                    <th>Customer</th><td><?= htmlspecialchars($All_Devicename[1] ?? '') ?></td>                    <th>WEG No</th><td><?= htmlspecialchars($All_WEG_No[1] ?? '') ?></td>                </tr>                <tr>                    <th>Site Location</th><td><?= htmlspecialchars($Site_Location[1] ?? '') ?></td>                    <th>LOC No</th><td><?= htmlspecialchars($All_LOC_No[1] ?? '') ?></td>                </tr>                <tr>                    <th>DOC</th><td><?= htmlspecialchars($DOC[1] ?? '') ?></td>                    <th>HTSC No</th><td><?= htmlspecialchars($All_HTSC_No[1] ?? '') ?></td>                </tr>            </table>            <div style="height:10px"></div>        <?php } else { ?>            <div class="section-header">Overview</div>        <?php } ?>        <?php        // KEEP ORIGINAL PHP LOGIC - only presenting in themed table/layout        if($_REQUEST['p'] == 2){                        if($FType==1