$FType==10){ ?>                            <?php if(($All_Devicename[1] ?? '') == 'KP Tex2'){ ?>                                <th style="text-align:center">Pressure</th>                                <th style="text-align:center">Pitch</th>                            <?php } else { ?>                                <th style="text-align:center">Reactive Power</th>                            <?php } ?>                        <?php } ?>                    </tr>                    </thead>                    <tbody>                    <?php                    while($Fetch_Result = $Mysql_Query_Result->fetch_array()) {                        echo "<tr>";                        echo "<td>".htmlspecialchars($Fetch_Result['Date_S']!=''?$Fetch_Result['Date_S']:'0')."</td>";                        echo "<td>".htmlspecialchars($Fetch_Result['Time_S']!=''?$Fetch_Result['Time_S']:'0')."</td>";                        echo "<td>".htmlspecialchars($Fetch_Result['GRPM']!=''?$Fetch_Result['GRPM']:'0')."</td>";                        echo "<td>".htmlspecialchars($Fetch_Result['RRPM']!=''?$Fetch_Result['RRPM']:'0')."</td>";                        echo "<td>".htmlspecialchars($Fetch_Result['WindSpeed']!=''?$Fetch_Result['WindSpeed']:'0')."</td>";                        echo "<td>".htmlspecialchars($Fetch_Result['Power']!=''?$Fetch_Result['Power']:'0')."</td>";                        echo "<td>".htmlspecialchars($Fetch_Result['Status']!=''?$Fetch_Result['Status']:'0')."</td>";                        if($FType==1 || $FType==6 || $FType==10){                            echo "<td>".htmlspecialchars($Fetch_Result['Pitch']!=''?$Fetch_Result['Pitch']:'0')."</td>";                        }                        if($FType==9){                            $devicedata = explode(' ', $Fetch_Result['OPC_ID']);                            echo "<td>".htmlspecialchars($Fetch_Result['Prev_P_Kwh']!=''?$Fetch_Result['Prev_P_Kwh']:'0')."</td>";                            echo "<td>".htmlspecialchars($Fetch_Result['Prev_C_Kwh']!=''?$Fetch_Result['Prev_C_Kwh']:'0')."</td>";                            echo "<td>".htmlspecialchars($Fetch_Result['Prev_P_Kvarh']!=''?$Fetch_Result['Prev_P_Kvarh']:'0')."</td>";                            echo "<td>".htmlspecialchars($devicedata[0] ?? '0')."</td>";                            echo "<td>".htmlspecialchars($devicedata[1] ?? '0')."</td>";                            echo "<td>".htmlspecialchars($devicedata[2] ?? '0')."</td>";                        }                        if($FType==3 || $FType==7 || $FType==8 || $FType==10){                            if(($All_Devicename[1] ?? '')=='KP Tex2'){                                echo "<td>".htmlspecialchars($Fetch_Result['Reactive_Power']!=''?$Fetch_Result['Reactive_Power']:'0')."</td>";                                echo "<td>".htmlspecialchars($Fetch_Result['L_N_Voltage_R']!=''?$Fetch_Result['L_N_Voltage_R']:'0')."</td>";                            } else {                                echo "<td>".htmlspecialchars($Fetch_Result['Reactive_Power']!=''?$Fetch_Result['Reactive_Power']:'0')."</td>";                            }                        }                        echo "</tr>";                    }                    ?>                    </tbody>                </table>        <?php            } else {                echo "<div class='no-records'>Records Not Found</div>";            }        }        ?>    </div></div><script>// Prevent default right-click to match original behavior (optional)document.addEventListener('contextmenu', event => {    // event.preventDefault();});// CSV exportdocument.getElementById('btnExportCSV').addEventListener('click', function(){    var table = document.getElementById('overview-table') || document.querySelector('.compact-table');    if(!table){ alert('No table to export'); return; }    var rows = [];    table.querySelectorAll('tr').forEach(function(tr){        var cols = [];        tr.querySelectorAll('th,td').forEach(function(td){ cols.push(td.innerText.trim()); });        rows.push(cols.join(','));    });    var csv = rows.join("\n");    var blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });    var link = document.createElement("a");    link.href = URL.createObjectURL(blob);    link.download = "overview_<?= preg_replace('/[^A-Za-z0-9]/','_', ($All_Devicename[1] ?? $IMEI)) ?>_<?= date('Y-m-d') ?>.csv";    document.body.appendChild(link);    link.click();    document.body.removeChild(link);});// PDF export using html2canvas + jsPDF (ensure background white and useCORS)document.getElementById('btnExportPDF').addEventListener('click', function(){    const element = document.querySelector('.report-card');    if(!element){ alert('No content to export'); return; }    html2canvas(element, { scale: 2, useCORS: true, backgroundColor: '#ffffff' }).then(canvas => {        const imgData = canvas.toDataURL('image/png');        const { jsPDF } = window.jspdf;        const pdf = new jsPDF('p', 'pt', 'a4');        const pageWidth = pdf.internal.pageSize.getWidth();        const pageHeight = pdf.internal.pageSize.getHeight();        const imgWidth = pageWidth - 40;        const imgHeight = (canvas.height * imgWidth) / canvas.width;        let position = 20;        if (imgHeight <= pageHeight - 40) {            pdf.addImage(imgData, 'PNG', 20, position, imgWidth, imgHeight);        } else {            let heightLeft = imgHeight;            let y = 20;            while (heightLeft > 0) {                pdf.addImage(imgData, 'PNG', 20, y, imgWidth, imgHeight);                heightLeft -= (pageHeight - 40);                if (heightLeft > 0) pdf.addPage();                y = 20 - (imgHeight - heightLeft);            }        }        pdf.save('overview_<?= preg_replace('/[^A-Za-z0-9]/','_', ($All_Devicename[1] ?? $IMEI)) ?>_<?= date('Y-m-d') ?>.pdf');    }).catch(err => {        alert('Could not export PDF: ' + err.message);    });});</script></body></html>